# This will keep the socket from closing, especially when listening to the user channel    

# Please add this method to the WebsocketClient class
def keepalive(self, interval=30):
    while not self.stop:
        if self.ws:
            self.ws.ping("keepalive")
            time.sleep(interval)

# create a thread before the while loop in the _listen method
def _listen(self):
    Thread(target=self.keepalive).start()
    while not self.stop:
        try:
            data = self.ws.recv()
            msg = json.loads(data)
        except ValueError as e:
            self.on_error(e)
        except Exception as e:
            self.on_error(e)
        else:
            self.on_message(msg)

This is handy to keep a set of views in sync with BigQuery (e.g. from a CD pipeline).

Example task:
```python
import luigi.contrib.bigquery as bigquery

class BQView(bigquery.BigqueryCreateViewTask):
    view='''SELECT * FROM [dataset.table] LIMIT 10'''

    def output(self):
        return bigquery.BigqueryTarget('project_id', 'dataset', 'view')
```

